   486→async function fetchLatestDecisions(runs: RunListItem[], errors: DashboardError[]) {
   487→  const results = await Promise.all(
   488→    runs.map(async (run) => {
   489→      const result = await getLatestRunDecision(run.id);
   490→      if (!result.success) {
   491→        if (result.error.kind !== 'not_found') {
   492→          errors.push({ source: `Decision ${run.id}`, error: result.error });
   493→        }
   494→        return null;
   495→      }
   496→      return {
   497→        runId: run.id,
   498→        runName: run.name,
   499→        decision: result.data,
   500→      };
   501→    }),
   502→  );
   503→
   504→  return results.filter((item): item is LatestDecision => item !== null);
   505→}
   506→
   507→function collectError<T>(
   508→  errors: DashboardError[],
   509→  source: string,
   510→  result: { success: true; data: T } | { success: false; error: ApiError },
   511→) {
   512→  if (!result.success) {
   513→    errors.push({ source, error: result.error });
   514→  }
   515→}
   516→
   517→function buildRunSummary(dashboard: DashboardState) {
   518→  const rejectedOptimization = dashboard.optimizationRuns.filter((run) =>
   519→    isRejectedResultStatus(run.result_status),
   520→  ).length;
   521→  const rejectedRuns = dashboard.runs.filter((run) => isRejectedResultStatus(run.classification)).length;
   522→  const completedRuns =
   523→    dashboard.runs.filter((run) => isCompletedStatus(run.status)).length +
   524→    dashboard.optimizationRuns.filter((run) => isCompletedStatus(run.status)).length;
   525→  const controlledFailures =
   526→    dashboard.runs.filter((run) => isControlledFailure(run.status)).length +
   527→    dashboard.optimizationRuns.filter((run) => isControlledFailure(run.status)).length;
   528→
   529→  return {
   530→    baselineRuns: dashboard.baselineRuns.length,
   531→    optimizationRuns: dashboard.optimizationRuns.length,
   532→    completedRuns,
   533→    controlledFailures,
   534→    rejectedResults: rejectedRuns + rejectedOptimization,
   535→    totalRecords: dashboard.runs.length + dashboard.optimizationRuns.length,
   536→  };
   537→}
   538→
   539→function findLatestRun(dashboard: DashboardState): ActivityItem | null {
   540→  const items = [
   541→    ...dashboard.runs.map(toRunActivity),
   542→    ...dashboard.optimizationRuns.map(toOptimizationActivity),
   543→  ].filter((item) => item.timestamp);
   544→
   545→  return items.sort((left, right) => compareDateDesc(left.timestamp, right.timestamp))[0] ?? null;
   546→}
   547→
   548→function buildRunsByStatus(dashboard: DashboardState): ChartDatum[] {
   549→  return countBy([
   550→    ...dashboard.runs.map((run) => run.status),
   551→    ...dashboard.optimizationRuns.map((run) => run.status),
   552→  ]);
   553→}
   554→
   555→function buildResultStatusDistribution(dashboard: DashboardState): ChartDatum[] {
   556→  return countBy([
