   598→function countBy(values: string[]): ChartDatum[] {
   599→  const counts = new Map<string, number>();
   600→  for (const value of values) {
   601→    const label = value || 'unknown';
   602→    counts.set(label, (counts.get(label) ?? 0) + 1);
