     9→  enabled?: boolean;
    10→  respectReducedMotion?: boolean;
    11→}
    12→
    13→export interface PollingResult {
    14→  status: string;
    15→  currentStage?: string;
    16→  resultStatus?: string;
    17→  classification?: string;
    18→  updatedAt?: string;
    19→  isPolling: boolean;
    20→  error: string | null;
    21→  refresh: () => void;
    22→}
    23→
    24→// Terminal states - polling stops when these are reached
    25→const BASELINE_TERMINAL_STATES = ['completed', 'failed', 'rejected', 'controlled_failure', 'error'];
    26→const OPTIMIZATION_TERMINAL_STATES = ['completed', 'optimization_rejected', 'failed', 'controlled_failure', 'error'];
    27→
    28→function isTerminalState(status: string, runType: RunType): boolean {
    29→  const terminalStates = runType === 'baseline' ? BASELINE_TERMINAL_STATES : OPTIMIZATION_TERMINAL_STATES;
    30→  return terminalStates.includes(status);
    31→}
    32→
    33→export function useRunPolling(runType: RunType, runId: string | null, options: PollingOptions = {}): PollingResult {
    34→  const {
    35→    interval = 2000,
    36→    enabled = true,
    37→    respectReducedMotion = true,
    38→  } = options;
    39→
    40→  const [status, setStatus] = useState<string>('idle');
    41→  const [currentStage, setCurrentStage] = useState<string | undefined>();
    42→  const [resultStatus, setResultStatus] = useState<string | undefined>();
    43→  const [classification, setClassification] = useState<string | undefined>();
    44→  const [updatedAt, setUpdatedAt] = useState<string | undefined>();
    45→  const [isPolling, setIsPolling] = useState(false);
    46→  const [error, setError] = useState<string | null>(null);
    47→
    48→  const intervalRef = useRef<NodeJS.Timeout | null>(null);
    49→  const isMountedRef = useRef(true);
    50→
    51→  // Check if user prefers reduced motion
    52→  const prefersReducedMotion = respectReducedMotion
    53→    ? typeof window !== 'undefined' && window.matchMedia('(prefers-reduced-motion: reduce)').matches
    54→    : false;
    55→
    56→  // Adjust interval for reduced motion
    57→  const effectiveInterval = prefersReducedMotion ? interval * 2 : interval;
    58→
    59→  // Fetch status function using API client
    60→  const fetchStatus = useCallback(async () => {
    61→    if (!runId || !isMountedRef.current) return;
    62→
    63→    try {
    64→      let data;
    65→      if (runType === 'baseline') {
    66→        const result = await getBaselineStatus(runId);
    67→        if (!result.success) {
    68→          throw new Error(result.error?.message || 'Failed to fetch baseline status');
    69→        }
    70→        data = result.data;
    71→      } else {
    72→        const result = await getOptimizationStatus(runId);
    73→        if (!result.success) {
    74→          throw new Error(result.error?.message || 'Failed to fetch optimization status');
    75→        }
    76→        data = result.data;
    77→      }
    78→
    79→      if (isMountedRef.current && data) {
    80→        setStatus(data.status || 'unknown');
    81→        setCurrentStage(data.current_stage || undefined);
    82→        // result_status only exists in OptimizationRunListItem, not status responses
    83→        setResultStatus(data.status);
    84→        // classification only exists for baseline runs
    85→        if (runType === 'baseline' && 'classification' in data) {
    86→          setClassification((data as { classification?: string | null }).classification || data.status);
    87→        } else {
    88→          setClassification(data.status);
    89→        }
    90→        // updated_at only exists for optimization runs
    91→        if (runType === 'optimization' && 'updated_at' in data) {
    92→          setUpdatedAt((data as { updated_at?: string }).updated_at);
    93→        } else {
    94→          setUpdatedAt(undefined);
    95→        }
    96→
    97→        // Clear error on successful fetch
    98→        setError(null);
    99→
   100→        // Check if terminal state reached
   101→        if (isTerminalState(data.status || 'unknown', runType)) {
   102→          setIsPolling(false);
   103→          if (intervalRef.current) {
   104→            clearInterval(intervalRef.current);
   105→            intervalRef.current = null;
   106→          }
   107→        }
   108→      }
   109→    } catch (e) {
   110→      if (isMountedRef.current) {
   111→        setError(e instanceof Error ? e.message : 'Failed to fetch status');
   112→        // Don't stop polling on network errors - may be transient
   113→      }
   114→    }
   115→  }, [runId, runType]);
   116→
   117→  // Manual refresh function
   118→  const refresh = useCallback(() => {
   119→    if (!isPolling) {
   120→      setIsPolling(true);
   121→    }
   122→    fetchStatus();
   123→  }, [isPolling, fetchStatus]);
   124→
   125→  // Start polling
   126→  useEffect(() => {
   127→    if (!runId || !enabled || isTerminalState(status, runType)) {
   128→      return;
   129→    }
   130→
   131→    // Set up interval first
   132→    intervalRef.current = setInterval(() => {
   133→      fetchStatus();
   134→    }, effectiveInterval);
   135→
   136→    // Set polling state and initial fetch in next tick to avoid synchronous setState
   137→    const timeoutId = setTimeout(() => {
   138→      setIsPolling(true);
   139→      fetchStatus();
   140→    }, 0);
   141→
   142→    // Cleanup on unmount
   143→    return () => {
   144→      if (intervalRef.current) {
   145→        clearInterval(intervalRef.current);
   146→        intervalRef.current = null;
   147→      }
   148→      clearTimeout(timeoutId);
   149→      isMountedRef.current = false;
   150→    };
   151→  }, [runId, runType, enabled, effectiveInterval, status, fetchStatus]);
   152→
   153→  // Cleanup on unmount
   154→  useEffect(() => {
   155→    return () => {
   156→      isMountedRef.current = false;
   157→    };
   158→  }, []);
   159→
   160→  return {
   161→    status,
   162→    currentStage,
   163→    resultStatus,
   164→    classification,
   165→    updatedAt,
   166→    isPolling,
   167→    error,
   168→    refresh,
   169→  };
   170→}
