    39→  if (['running', 'info'].includes(normalized)) {
    40→    return 'info';
    41→  }
    42→  if (['warning', 'unknown', 'failed_controlled', 'confirmation_required'].includes(normalized)) {
    43→    return 'warning';
    44→  }
    45→  if (['failed', 'missing', 'rejected', 'system_failed'].includes(normalized)) {
