'use client';

import Link from 'next/link';
import { usePathname } from 'next/navigation';

interface NavItem {
  name: string;
  path: string;
  code: string;
}

interface NavGroup {
  label: string;
  items: NavItem[];
}

const navGroups: NavGroup[] = [
  {
    label: 'Discover',
    items: [
      { name: 'Dashboard', path: '/', code: 'DB' },
      { name: 'Strategy Journey', path: '/journey', code: 'JN' },
      { name: 'Strategies', path: '/strategies', code: 'ST' },
    ],
  },
  {
    label: 'Test',
    items: [
      { name: 'Runs', path: '/runs', code: 'RN' },
      { name: 'Baseline', path: '/baseline', code: 'BL' },
      { name: 'Optimization', path: '/optimization', code: 'OP' },
      { name: 'Validation', path: '/validation', code: 'VL' },
    ],
  },
  {
    label: 'Evidence',
    items: [
      { name: 'Results', path: '/results', code: 'RS' },
      { name: 'Reports', path: '/reports', code: 'RP' },
    ],
  },
  {
    label: 'System',
    items: [
      { name: 'Settings', path: '/settings', code: 'SE' },
    ],
  },
];

export default function Sidebar() {
  const pathname = usePathname();

  function isActive(path: string) {
    return path === '/' ? pathname === '/' : pathname.startsWith(path);
  }

  return (
    <aside className="flex w-60 shrink-0 flex-col border-r border-[var(--app-border)] bg-[var(--app-surface-muted)]">
      <div className="border-b border-[var(--app-border)] px-4 py-4">
        <div className="flex items-center gap-3">
          <div className="flex h-9 w-9 items-center justify-center rounded-[var(--app-radius)] border border-[var(--app-accent-border)] bg-[var(--app-accent-soft)] text-xs font-bold tracking-wider text-[var(--app-accent)]">
            HER
          </div>
          <div>
            <h1 className="text-sm font-semibold text-[var(--app-text)]">Command Center</h1>
            <p className="text-[11px] text-[var(--app-text-subtle)]">Strategy discovery</p>
          </div>
        </div>
      </div>

      <nav className="flex-1 overflow-auto px-3 py-3" aria-label="Primary navigation">
        <div className="space-y-5">
          {navGroups.map((group) => (
            <div key={group.label}>
              <p className="mb-1 px-2 text-[10px] font-semibold uppercase tracking-widest text-[var(--app-text-subtle)]">
                {group.label}
              </p>
              <ul className="space-y-0.5">
                {group.items.map((item) => {
                  const active = isActive(item.path);
                  return (
                    <li key={item.path}>
                      <Link
                        href={item.path}
                        className={[
                          'flex h-9 items-center gap-2.5 rounded-[var(--app-radius)] px-2.5 text-sm font-medium transition-colors',
                          active
                            ? 'border border-[var(--app-accent-border)] bg-[var(--app-accent-soft)] text-[var(--app-accent)]'
                            : 'border border-transparent text-[var(--app-text-muted)] hover:bg-[var(--app-surface)] hover:text-[var(--app-text)]',
                        ].join(' ')}
                      >
                        <span className={[
                          'flex h-5 w-6 items-center justify-center rounded text-[9px] font-semibold',
                          active
                            ? 'bg-[var(--app-accent-soft)] text-[var(--app-accent)]'
                            : 'bg-[var(--app-surface)] text-[var(--app-text-subtle)]',
                        ].join(' ')}>
                          {item.code}
                        </span>
                        {item.name}
                      </Link>
                    </li>
                  );
                })}
              </ul>
            </div>
          ))}
        </div>
      </nav>

      <div className="border-t border-[var(--app-border)] p-3">
        <p className="text-[11px] leading-5 text-[var(--app-text-subtle)]">
          Evidence only. No live trading actions.
        </p>
      </div>
    </aside>
  );
}

import { ReactNode } from 'react';

export type StepStatus = 'not_started' | 'running' | 'passed' | 'failed' | 'blocked' | 'skipped';

export interface WorkflowStep {
  id: string;
  label: string;
  status: StepStatus;
  message?: string;
  timestamp?: string | null;
  href?: string;
}

interface WorkflowStepperProps {
  steps: WorkflowStep[];
  orientation?: 'horizontal' | 'vertical';
}

const statusConfig: Record<StepStatus, { icon: ReactNode; classes: string; dotClasses: string }> = {
  not_started: {
    icon: <span className="text-[10px] font-bold">–</span>,
    classes: 'border-[var(--app-border)] bg-[var(--app-surface-muted)] text-[var(--app-text-subtle)]',
    dotClasses: 'bg-[var(--app-border)]',
  },
  running: {
    icon: <span className="text-[10px] font-bold animate-pulse">▶</span>,
    classes: 'border-[rgb(56_189_248_/_0.4)] bg-[rgb(56_189_248_/_0.10)] text-[var(--app-info)]',
    dotClasses: 'bg-[var(--app-info)]',
  },
  passed: {
    icon: <span className="text-[10px] font-bold">✓</span>,
    classes: 'border-[rgb(34_197_94_/_0.4)] bg-[rgb(34_197_94_/_0.10)] text-[var(--app-success)]',
    dotClasses: 'bg-[var(--app-success)]',
  },
  failed: {
    icon: <span className="text-[10px] font-bold">✕</span>,
    classes: 'border-[rgb(239_68_68_/_0.4)] bg-[rgb(239_68_68_/_0.10)] text-[var(--app-danger)]',
    dotClasses: 'bg-[var(--app-danger)]',
  },
  blocked: {
    icon: <span className="text-[10px] font-bold">⊘</span>,
    classes: 'border-[rgb(245_158_11_/_0.4)] bg-[rgb(245_158_11_/_0.10)] text-[var(--app-warning)]',
    dotClasses: 'bg-[var(--app-warning)]',
  },
  skipped: {
    icon: <span className="text-[10px] font-bold">→</span>,
    classes: 'border-[var(--app-border)] bg-[var(--app-surface-muted)] text-[var(--app-text-subtle)]',
    dotClasses: 'bg-[var(--app-border)]',
  },
};

function formatTs(ts: string | null | undefined): string | null {
  if (!ts) return null;
  try {
    return new Date(ts).toLocaleString(undefined, {
      month: 'short',
      day: 'numeric',
      hour: '2-digit',
      minute: '2-digit',
    });
  } catch {
    return ts;
  }
}

export default function WorkflowStepper({ steps, orientation = 'vertical' }: WorkflowStepperProps) {
  if (orientation === 'horizontal') {
    return (
      <div className="flex items-start gap-0 overflow-x-auto">
        {steps.map((step, index) => {
          const cfg = statusConfig[step.status];
          const isLast = index === steps.length - 1;
          return (
            <div key={step.id} className="flex min-w-0 shrink-0 items-start">
              <div className="flex flex-col items-center">
                <div className={[
                  'flex h-8 w-8 shrink-0 items-center justify-center rounded-full border',
                  cfg.classes,
                ].join(' ')}>
                  {cfg.icon}
                </div>
                <div className="mt-2 px-2 text-center">
                  {step.href ? (
                    <a href={step.href} className="text-xs font-medium text-[var(--app-text)] hover:text-[var(--app-accent)] transition-colors">
                      {step.label}
                    </a>
                  ) : (
                    <p className="text-xs font-medium text-[var(--app-text-muted)]">{step.label}</p>
                  )}
                  {step.message && (
                    <p className="mt-0.5 text-[11px] text-[var(--app-text-subtle)]">{step.message}</p>
                  )}
                  {step.timestamp && (
                    <p className="mt-0.5 text-[10px] text-[var(--app-text-subtle)]">{formatTs(step.timestamp)}</p>
                  )}
                </div>
              </div>
              {!isLast && (
                <div className="mt-4 h-px w-8 shrink-0 bg-[var(--app-border)]" />
              )}
            </div>
          );
        })}
      </div>
    );
  }

  return (
    <div className="space-y-0">
      {steps.map((step, index) => {
        const cfg = statusConfig[step.status];
        const isLast = index === steps.length - 1;
        return (
          <div key={step.id} className="flex gap-3">
            <div className="flex flex-col items-center">
              <div className={[
                'flex h-8 w-8 shrink-0 items-center justify-center rounded-full border',
                cfg.classes,
              ].join(' ')}>
                {cfg.icon}
              </div>
              {!isLast && (
                <div className="w-px flex-1 bg-[var(--app-border)] my-1" style={{ minHeight: '24px' }} />
              )}
            </div>
            <div className="min-w-0 pb-5 pt-1">
              {step.href ? (
                <a href={step.href} className="text-sm font-semibold text-[var(--app-text)] hover:text-[var(--app-accent)] transition-colors">
                  {step.label}
                </a>
              ) : (
                <p className="text-sm font-semibold text-[var(--app-text)]">{step.label}</p>
              )}
              {step.message && (
                <p className="mt-0.5 text-xs leading-5 text-[var(--app-text-muted)]">{step.message}</p>
              )}
              {step.timestamp && (
                <p className="mt-0.5 text-[11px] text-[var(--app-text-subtle)]">{formatTs(step.timestamp)}</p>
              )}
            </div>
          </div>
        );
      })}
    </div>
  );
}

'use client';

import { useRunPolling, RunType } from '@/hooks/useRunPolling';
import StatusBadge from './StatusBadge';

interface LiveRunPanelProps {
  runType: RunType;
  runId: string;
  label?: string;
}

const STAGE_LABEL: Record<string, string> = {
  data_download: 'Downloading data',
  backtest: 'Running backtest',
  parse_result: 'Parsing results',
  evaluate: 'Evaluating metrics',
  decision: 'Recording decision',
  hyperopt: 'Running hyperopt',
  validate_candidate: 'Validating candidate',
  optimize: 'Optimizing',
  compare: 'Comparing results',
};

function stageLabel(key: string | undefined): string {
  if (!key) return 'Processing';
  return STAGE_LABEL[key] ?? key.replace(/_/g, ' ');
}

function isTerminal(status: string): boolean {
  return ['completed', 'failed', 'optimization_rejected', 'rejected', 'controlled_failure', 'error'].includes(status);
}

export default function LiveRunPanel({ runType, runId, label }: LiveRunPanelProps) {
  const { status, currentStage, updatedAt, isPolling, error, refresh } = useRunPolling(runType, runId);

  const terminal = isTerminal(status);
  const alive = !terminal && status !== 'idle';

  function updatedLabel(): string {
    if (!updatedAt) return '';
    try {
      return new Date(updatedAt).toLocaleTimeString(undefined, { hour: '2-digit', minute: '2-digit', second: '2-digit' });
    } catch {
      return updatedAt;
    }
  }

  return (
    <div className="rounded-[var(--app-radius)] border border-[var(--app-accent-border)] bg-[var(--app-accent-soft)] p-4">
      <div className="flex items-center justify-between gap-3">
        <div className="flex items-center gap-3 min-w-0">
          {alive && (
            <span className="relative flex h-2.5 w-2.5 shrink-0">
              <span className="absolute inline-flex h-full w-full animate-ping rounded-full bg-[var(--app-accent)] opacity-60" />
              <span className="relative inline-flex h-2.5 w-2.5 rounded-full bg-[var(--app-accent)]" />
            </span>
          )}
          <div className="min-w-0">
            <p className="text-sm font-semibold text-[var(--app-accent)]">
              {label ?? (runType === 'baseline' ? 'Baseline run' : 'Optimization run')}
            </p>
            <p className="mt-0.5 font-mono text-[11px] text-[var(--app-text-subtle)]">{runId}</p>
          </div>
        </div>
        <StatusBadge status={status} tone={alive ? 'info' : terminal ? (status === 'completed' ? 'success' : 'warning') : 'neutral'} />
      </div>

      {currentStage && (
        <div className="mt-3 flex items-center gap-2">
          <span className="text-xs text-[var(--app-text-muted)]">Current stage:</span>
          <span className="text-xs font-medium text-[var(--app-text)]">{stageLabel(currentStage)}</span>
        </div>
      )}

      <div className="mt-3 flex items-center justify-between gap-3">
        <div className="flex items-center gap-3">
          {isPolling && (
            <span className="text-[11px] text-[var(--app-text-subtle)]">Polling every 2 s</span>
          )}
          {updatedAt && (
            <span className="text-[11px] text-[var(--app-text-subtle)]">
              Last updated {updatedLabel()}
            </span>
          )}
        </div>
        {!isPolling && (
          <button
            onClick={refresh}
            className="rounded-[var(--app-radius)] border border-[var(--app-border)] bg-[var(--app-surface)] px-2.5 py-1 text-xs text-[var(--app-text-muted)] hover:text-[var(--app-text)] transition-colors"
          >
            Retry
          </button>
        )}
      </div>

      {error && (
        <p className="mt-2 text-xs text-[var(--app-danger)]">Polling error: {error}</p>
      )}
    </div>
  );
}

import { ReactNode } from 'react';

interface NextAction {
  id: string;
  label: string;
  description: string;
  onClick?: () => void;
  href?: string;
  disabled?: boolean;
  tone?: 'primary' | 'secondary' | 'warning';
}

interface NextActionPanelProps {
  title?: string;
  message?: string;
  actions?: NextAction[];
  children?: ReactNode;
}

export default function NextActionPanel({
  title = 'Next safe action',
  message,
  actions = [],
  children,
}: NextActionPanelProps) {
  return (
    <div className="rounded-[var(--app-radius)] border border-[var(--app-border)] bg-[var(--app-surface)] p-5">
      <div className="flex items-start gap-3">
        <div className="flex h-8 w-8 shrink-0 items-center justify-center rounded-full border border-[rgb(56_189_248_/_0.32)] bg-[rgb(56_189_248_/_0.10)]">
          <span className="text-xs font-bold text-[var(--app-info)]">→</span>
        </div>
        <div className="min-w-0 flex-1">
          <h3 className="text-sm font-semibold text-[var(--app-text)]">{title}</h3>
          {message && (
            <p className="mt-1 text-sm leading-6 text-[var(--app-text-muted)]">{message}</p>
          )}
          {children && <div className="mt-2">{children}</div>}
          {actions.length > 0 && (
            <div className="mt-4 flex flex-wrap gap-2">
              {actions.map((action) => {
                const baseClasses = 'rounded-[var(--app-radius)] px-3.5 py-2 text-sm font-medium transition-colors disabled:opacity-50 disabled:cursor-not-allowed';
                const toneClasses =
                  action.tone === 'primary'
                    ? 'bg-[var(--app-accent)] text-[var(--app-accent-text)] hover:bg-[var(--app-accent-strong)]'
                    : action.tone === 'warning'
                    ? 'border border-[rgb(245_158_11_/_0.4)] bg-[rgb(245_158_11_/_0.10)] text-[var(--app-warning)] hover:bg-[rgb(245_158_11_/_0.18)]'
                    : 'border border-[var(--app-border)] bg-[var(--app-surface-muted)] text-[var(--app-text-muted)] hover:text-[var(--app-text)]';

                if (action.href && !action.disabled) {
                  return (
                    <a key={action.id} href={action.href} className={`${baseClasses} ${toneClasses}`}>
                      {action.label}
                    </a>
                  );
                }
                return (
                  <div key={action.id} className="group relative">
                    <button
                      onClick={action.onClick}
                      disabled={action.disabled}
                      className={`${baseClasses} ${toneClasses}`}
                    >
                      {action.label}
                    </button>
                    {action.description && (
                      <div className="absolute bottom-full left-0 mb-1 hidden w-64 rounded-[var(--app-radius)] border border-[var(--app-border)] bg-[var(--app-surface-raised)] p-2 text-xs text-[var(--app-text-muted)] shadow-lg group-hover:block z-10">
                        {action.description}
                      </div>
                    )}
                  </div>
                );
              })}
            </div>
          )}
        </div>
      </div>
    </div>
  );
}

import SectionCard from './SectionCard';
import StatusBadge from './StatusBadge';
import type { ValidationEvidence } from '@/lib/api/types';

interface OOSValidationCardProps {
  evidence?: ValidationEvidence;
}

function fmt(val: unknown, percent = false): string {
  if (val === undefined || val === null) return 'N/A';
  const n = Number(val);
  if (!isFinite(n)) return String(val);
  if (percent) return `${n.toFixed(1)}%`;
  return n.toFixed(3);
}

export default function OOSValidationCard({ evidence }: OOSValidationCardProps) {
  if (!evidence) {
    return (
      <SectionCard title="Out-of-Sample Validation">
        <p className="text-sm text-[var(--app-text-subtle)]">No OOS evidence available from the backend for this run.</p>
      </SectionCard>
    );
  }

  const metrics = evidence.metrics as Record<string, unknown>;
  const isPassed = evidence.status === 'oos_passed';

  return (
    <SectionCard
      title="Out-of-Sample Validation"
      description="OOS tests strategy performance on unseen historical data withheld from training."
      actions={<StatusBadge status={isPassed ? 'passed' : 'failed'} tone={isPassed ? 'success' : 'danger'} label={isPassed ? 'Passed' : 'Failed'} />}
    >
      <div className="space-y-4">
        {evidence.timerange && (
          <div>
            <p className="text-xs text-[var(--app-text-subtle)]">OOS timerange</p>
            <p className="mt-0.5 font-mono text-sm text-[var(--app-text)]">{evidence.timerange}</p>
          </div>
        )}

        <div className="grid grid-cols-2 gap-3">
          {[
            { label: 'Profit factor', key: 'profit_factor' },
            { label: 'Expectancy', key: 'expectancy' },
            { label: 'Max drawdown', key: 'max_drawdown_pct', percent: true },
            { label: 'Trades', key: 'trade_count' },
          ].map(({ label, key, percent }) => (
            <div key={key} className="rounded-[var(--app-radius)] border border-[var(--app-border)] bg-[var(--app-surface-muted)] p-3">
              <p className="text-xs text-[var(--app-text-subtle)]">{label}</p>
              <p className="mt-1 text-lg font-semibold text-[var(--app-text)]">{fmt(metrics[key], percent)}</p>
            </div>
          ))}
        </div>

        {evidence.issues && evidence.issues.length > 0 && (
          <div>
            <p className="text-xs font-semibold text-[var(--app-danger)] mb-1">Issues</p>
            <ul className="space-y-1">
              {evidence.issues.map((issue, idx) => (
                <li key={idx} className="text-xs text-[var(--app-text-muted)] flex gap-2">
                  <span className="text-[var(--app-danger)] shrink-0">•</span>
                  {issue.message}
                </li>
              ))}
            </ul>
          </div>
        )}

        {evidence.warnings && evidence.warnings.length > 0 && (
          <div>
            <p className="text-xs font-semibold text-[var(--app-warning)] mb-1">Warnings</p>
            <ul className="space-y-1">
              {evidence.warnings.map((warning, idx) => (
                <li key={idx} className="text-xs text-[var(--app-text-muted)] flex gap-2">
                  <span className="text-[var(--app-warning)] shrink-0">•</span>
                  {warning}
                </li>
              ))}
            </ul>
          </div>
        )}
      </div>
    </SectionCard>
  );
}

import SectionCard from './SectionCard';
import StatusBadge from './StatusBadge';
import type { ValidationEvidence } from '@/lib/api/types';

interface WFOValidationCardProps {
  evidence?: ValidationEvidence;
  windows?: ValidationEvidence[];
}

function fmt(val: unknown): string {
  if (val === undefined || val === null) return 'N/A';
  const n = Number(val);
  if (!isFinite(n)) return String(val);
  return n.toFixed(3);
}

export default function WFOValidationCard({ evidence, windows }: WFOValidationCardProps) {
  if (!evidence && (!windows || windows.length === 0)) {
    return (
      <SectionCard title="Walk-Forward Validation">
        <p className="text-sm text-[var(--app-text-subtle)]">No WFO evidence available from the backend for this run.</p>
      </SectionCard>
    );
  }

  const isPassed = evidence?.status === 'wfo_passed';
  const totalWindows = windows?.length ?? 0;
  const passedWindows = windows?.filter((w) => w.status === 'wfo_passed').length ?? 0;
  const failedWindows = windows?.filter((w) => w.status === 'wfo_failed').length ?? 0;
  const passRate = totalWindows > 0 ? (passedWindows / totalWindows) * 100 : 0;

  return (
    <SectionCard
      title="Walk-Forward Validation"
      description="WFO evaluates strategy consistency across sequential time windows."
      actions={<StatusBadge status={isPassed ? 'passed' : 'failed'} tone={isPassed ? 'success' : 'danger'} label={isPassed ? 'Passed' : 'Failed'} />}
    >
      <div className="space-y-4">
        <div className="grid grid-cols-3 gap-3">
          <div className="rounded-[var(--app-radius)] border border-[var(--app-border)] bg-[var(--app-surface-muted)] p-3">
            <p className="text-xs text-[var(--app-text-subtle)]">Windows</p>
            <p className="mt-1 text-lg font-semibold text-[var(--app-text)]">{totalWindows}</p>
          </div>
          <div className="rounded-[var(--app-radius)] border border-[var(--app-border)] bg-[var(--app-surface-muted)] p-3">
            <p className="text-xs text-[var(--app-text-subtle)]">Passed</p>
            <p className="mt-1 text-lg font-semibold text-[var(--app-success)]">{passedWindows}</p>
          </div>
          <div className="rounded-[var(--app-radius)] border border-[var(--app-border)] bg-[var(--app-surface-muted)] p-3">
            <p className="text-xs text-[var(--app-text-subtle)]">Failed</p>
            <p className="mt-1 text-lg font-semibold text-[var(--app-danger)]">{failedWindows}</p>
          </div>
        </div>

        <div className="rounded-[var(--app-radius)] border border-[var(--app-border)] bg-[var(--app-surface-muted)] p-3">
          <p className="text-xs text-[var(--app-text-subtle)]">Pass rate</p>
          <p className="mt-1 text-xl font-semibold text-[var(--app-text)]">{passRate.toFixed(1)}%</p>
          <div className="mt-2 h-1.5 rounded-full bg-[var(--app-border)]">
            <div
              className="h-1.5 rounded-full transition-all"
              style={{
                width: `${passRate}%`,
                background: passRate >= 60 ? 'var(--app-success)' : passRate >= 40 ? 'var(--app-warning)' : 'var(--app-danger)',
              }}
            />
          </div>
        </div>

        {windows && windows.length > 0 && (
          <div>
            <p className="mb-2 text-xs font-semibold text-[var(--app-text-muted)]">Window results</p>
            <div className="overflow-x-auto rounded-[var(--app-radius)] border border-[var(--app-border)]">
              <table className="min-w-full text-xs">
                <thead>
                  <tr className="border-b border-[var(--app-border)] bg-[var(--app-surface-muted)]">
                    <th className="px-3 py-2 text-left font-semibold text-[var(--app-text-subtle)]">Window</th>
                    <th className="px-3 py-2 text-left font-semibold text-[var(--app-text-subtle)]">Timerange</th>
                    <th className="px-3 py-2 text-left font-semibold text-[var(--app-text-subtle)]">Status</th>
                    <th className="px-3 py-2 text-left font-semibold text-[var(--app-text-subtle)]">Profit factor</th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-[var(--app-border)]">
                  {windows.map((win, idx) => {
                    const m = win.metrics as Record<string, unknown>;
                    const passed = win.status === 'wfo_passed';
                    return (
                      <tr key={idx} className="bg-[var(--app-surface)] hover:bg-[var(--app-surface-raised)]">
                        <td className="px-3 py-2 text-[var(--app-text)]">{win.window_index ?? idx + 1}</td>
                        <td className="px-3 py-2 font-mono text-[var(--app-text-subtle)]">{win.timerange ?? '—'}</td>
                        <td className="px-3 py-2">
                          <StatusBadge status={win.status} tone={passed ? 'success' : 'danger'} label={passed ? 'Passed' : 'Failed'} />
                        </td>
                        <td className="px-3 py-2 text-[var(--app-text)]">{fmt(m.profit_factor)}</td>
                      </tr>
                    );
                  })}
                </tbody>
              </table>
            </div>
          </div>
        )}

        {evidence?.issues && evidence.issues.length > 0 && (
          <div>
            <p className="text-xs font-semibold text-[var(--app-danger)] mb-1">Issues</p>
            <ul className="space-y-1">
              {evidence.issues.map((issue, idx) => (
                <li key={idx} className="text-xs text-[var(--app-text-muted)] flex gap-2">
                  <span className="text-[var(--app-danger)] shrink-0">•</span>
                  {issue.message}
                </li>
              ))}
            </ul>
          </div>
        )}

        {evidence?.warnings && evidence.warnings.length > 0 && (
          <div>
            <p className="text-xs font-semibold text-[var(--app-warning)] mb-1">Warnings</p>
            <ul className="space-y-1">
              {evidence.warnings.map((warning, idx) => (
                <li key={idx} className="text-xs text-[var(--app-text-muted)] flex gap-2">
                  <span className="text-[var(--app-warning)] shrink-0">•</span>
                  {warning}
                </li>
              ))}
            </ul>
          </div>
        )}
      </div>
    </SectionCard>
  );
}

import SectionCard from './SectionCard';
import StatusBadge from './StatusBadge';
import type { ValidationEvidence } from '@/lib/api/types';

interface RobustnessValidationCardProps {
  checks?: ValidationEvidence[];
}

export default function RobustnessValidationCard({ checks }: RobustnessValidationCardProps) {
  if (!checks || checks.length === 0) {
    return (
      <SectionCard title="Robustness Checks">
        <p className="text-sm text-[var(--app-text-subtle)]">No robustness evidence available from the backend for this run.</p>
      </SectionCard>
    );
  }

  const criticalFailures = checks.filter((c) => c.status === 'robustness_failed').length;
  const warnings = checks.filter((c) => c.status === 'robustness_warning').length;
  const passed = checks.filter((c) => c.status === 'robustness_passed').length;
  const overallStatus: 'passed' | 'warning' | 'failed' =
    criticalFailures > 0 ? 'failed' : warnings > 0 ? 'warning' : 'passed';

  const overallTone =
    overallStatus === 'passed' ? 'success' : overallStatus === 'warning' ? 'warning' : 'danger';

  return (
    <SectionCard
      title="Robustness Checks"
      description="Robustness checks verify the strategy behaves consistently under varied conditions."
      actions={<StatusBadge status={overallStatus} tone={overallTone} label={overallStatus === 'passed' ? 'Passed' : overallStatus === 'warning' ? 'Warning' : 'Failed'} />}
    >
      <div className="space-y-4">
        <div className="grid grid-cols-3 gap-3">
          <div className="rounded-[var(--app-radius)] border border-[var(--app-border)] bg-[var(--app-surface-muted)] p-3">
            <p className="text-xs text-[var(--app-text-subtle)]">Passed</p>
            <p className="mt-1 text-lg font-semibold text-[var(--app-success)]">{passed}</p>
          </div>
          <div className="rounded-[var(--app-radius)] border border-[var(--app-border)] bg-[var(--app-surface-muted)] p-3">
            <p className="text-xs text-[var(--app-text-subtle)]">Warnings</p>
            <p className="mt-1 text-lg font-semibold text-[var(--app-warning)]">{warnings}</p>
          </div>
          <div className="rounded-[var(--app-radius)] border border-[var(--app-border)] bg-[var(--app-surface-muted)] p-3">
            <p className="text-xs text-[var(--app-text-subtle)]">Failures</p>
            <p className="mt-1 text-lg font-semibold text-[var(--app-danger)]">{criticalFailures}</p>
          </div>
        </div>

        <div className="space-y-2">
          {checks.map((check, idx) => {
            const passed = check.status === 'robustness_passed';
            const warning = check.status === 'robustness_warning';
            const tone = passed ? 'success' : warning ? 'warning' : 'danger';
            return (
              <div
                key={idx}
                className="rounded-[var(--app-radius)] border border-[var(--app-border)] bg-[var(--app-surface-muted)] p-3"
              >
                <div className="flex items-center justify-between gap-3">
                  <p className="text-sm font-medium text-[var(--app-text)]">
                    {check.check_name ?? `Check ${idx + 1}`}
                  </p>
                  <StatusBadge status={check.status} tone={tone} label={passed ? 'Passed' : warning ? 'Warning' : 'Failed'} />
                </div>
                {check.timerange && (
                  <p className="mt-1 font-mono text-xs text-[var(--app-text-subtle)]">{check.timerange}</p>
                )}
                {check.issues && check.issues.length > 0 && (
                  <div className="mt-2">
                    <p className="text-xs font-semibold text-[var(--app-danger)] mb-1">Issues</p>
                    <ul className="space-y-0.5">
                      {check.issues.map((issue, i) => (
                        <li key={i} className="text-xs text-[var(--app-text-muted)] flex gap-2">
                          <span className="text-[var(--app-danger)] shrink-0">•</span>
                          {issue.message}
                        </li>
                      ))}
                    </ul>
                  </div>
                )}
                {check.warnings && check.warnings.length > 0 && (
                  <div className="mt-2">
                    <p className="text-xs font-semibold text-[var(--app-warning)] mb-1">Warnings</p>
                    <ul className="space-y-0.5">
                      {check.warnings.map((warning, i) => (
                        <li key={i} className="text-xs text-[var(--app-text-muted)] flex gap-2">
                          <span className="text-[var(--app-warning)] shrink-0">•</span>
                          {warning}
                        </li>
                      ))}
                    </ul>
                  </div>
                )}
              </div>
            );
          })}
        </div>
      </div>
    </SectionCard>
  );
}

'use client';

import { useCallback, useEffect, useMemo, useState } from 'react';
import AppShell from '@/components/AppShell';
import ControlledFailureBanner from '@/components/ControlledFailureBanner';
import EmptyState from '@/components/EmptyState';
import ErrorBanner from '@/components/ErrorBanner';
import LiveRunPanel from '@/components/LiveRunPanel';
import LoadingSkeleton from '@/components/LoadingSkeleton';
import NextActionPanel from '@/components/NextActionPanel';
import PageHeader from '@/components/PageHeader';
import SectionCard from '@/components/SectionCard';
import StatusBadge from '@/components/StatusBadge';
import WorkflowStepper, { WorkflowStep, StepStatus } from '@/components/WorkflowStepper';
import MetricCard from '@/components/MetricCard';
import {
  StrategySummary,
  OptimizationRunListItem,
  RunListItem,
  listStrategies,
  listBaselineRuns,
  listOptimizationRuns,
} from '@/lib/api';
import { listValidationRuns } from '@/lib/api/validation';
import type { ValidationRunListItem } from '@/lib/api/types';

interface JourneyState {
  strategies: StrategySummary[];
  baselineRuns: RunListItem[];
  optimizationRuns: OptimizationRunListItem[];
  validationRuns: ValidationRunListItem[];
  errors: string[];
  loadedAt: string | null;
}

const INITIAL: JourneyState = {
  strategies: [],
  baselineRuns: [],
  optimizationRuns: [],
  validationRuns: [],
  errors: [],
  loadedAt: null,
};

function fmtTs(ts: string | null | undefined): string {
  if (!ts) return '';
  try {
    return new Date(ts).toLocaleString(undefined, {
      month: 'short', day: 'numeric', hour: '2-digit', minute: '2-digit',
    });
  } catch {
    return ts;
  }
}

function isActiveStatus(status: string): boolean {
  return ['running', 'pending', 'queued'].includes(status);
}

function isCompleted(status: string | null | undefined): boolean {
  return status === 'completed' || status === 'passed';
}

function isFailed(status: string | null | undefined): boolean {
  return status === 'failed' || status === 'error';
}

function isRejected(status: string | null | undefined): boolean {
  return ['rejected', 'optimization_rejected', 'controlled_failure'].includes(status ?? '');
}

function readinessLabel(readiness: string): string {
  switch (readiness) {
    case 'ready': return 'Ready';
    case 'warning': return 'Warning';
    case 'missing_sidecar': return 'Missing sidecar';
    case 'invalid': return 'Invalid';
    case 'parse_error': return 'Parse error';
    case 'unsafe': return 'Unsafe';
    default: return readiness;
  }
}

function readinessTone(readiness: string): 'success' | 'warning' | 'danger' | 'neutral' {
  if (readiness === 'ready') return 'success';
  if (readiness === 'warning') return 'warning';
  if (['missing_sidecar', 'invalid', 'parse_error', 'unsafe'].includes(readiness)) return 'danger';
  return 'neutral';
}

export default function JourneyPage() {
  const [state, setState] = useState<JourneyState>(INITIAL);
  const [loading, setLoading] = useState(true);
  const [selectedStrategy, setSelectedStrategy] = useState<string>('');
  const [refreshing, setRefreshing] = useState(false);

  const load = useCallback(async (markRefreshing = true) => {
    if (markRefreshing) setRefreshing(true);

    const [stratResult, baselineResult, optResult, valResult] = await Promise.all([
      listStrategies({ limit: 200 }),
      listBaselineRuns({ limit: 500 }),
      listOptimizationRuns({ limit: 500 }),
      listValidationRuns({ limit: 500 }),
    ]);

    const errors: string[] = [];
    if (!stratResult.success) errors.push(`Strategies: ${stratResult.error.message}`);
    if (!baselineResult.success) errors.push(`Baseline runs: ${baselineResult.error.message}`);
    if (!optResult.success) errors.push(`Optimization runs: ${optResult.error.message}`);
    if (!valResult.success) errors.push(`Validation runs: ${valResult.error.message}`);

    const strategies = stratResult.success ? stratResult.data : [];
    const baselineRuns = baselineResult.success ? baselineResult.data : [];
    const optimizationRuns = optResult.success ? optResult.data : [];
    const validationRuns = valResult.success ? valResult.data : [];

    setState({ strategies, baselineRuns, optimizationRuns, validationRuns, errors, loadedAt: new Date().toISOString() });
    setLoading(false);
    if (markRefreshing) setRefreshing(false);

    if (strategies.length > 0 && !selectedStrategy) {
      setSelectedStrategy(strategies[0].strategy_name);
    }
  }, [selectedStrategy]);

  useEffect(() => {
    const t = window.setTimeout(() => { void load(false); }, 0);
    return () => window.clearTimeout(t);
  }, [load]);

  const strategy = useMemo(
    () => state.strategies.find((s) => s.strategy_name === selectedStrategy) ?? null,
    [state.strategies, selectedStrategy],
  );

  const strategyBaselines = useMemo(
    () => state.baselineRuns.filter(
      (r) => r.strategy_id === selectedStrategy || r.name?.includes(selectedStrategy),
    ).sort((a, b) => new Date(b.created_at).getTime() - new Date(a.created_at).getTime()),
    [state.baselineRuns, selectedStrategy],
  );

  const strategyOptimizations = useMemo(
    () => state.optimizationRuns.filter(
      (r) => r.strategy_name === selectedStrategy,
    ).sort((a, b) => new Date(b.created_at).getTime() - new Date(a.created_at).getTime()),
    [state.optimizationRuns, selectedStrategy],
  );

  const strategyValidations = useMemo(
    () => state.validationRuns.filter(
      (r) => r.strategy_name === selectedStrategy,
    ).sort((a, b) => new Date(b.created_at).getTime() - new Date(a.created_at).getTime()),
    [state.validationRuns, selectedStrategy],
  );

  const latestBaseline = strategyBaselines[0] ?? null;
  const latestOptimization = strategyOptimizations[0] ?? null;
  const latestValidation = strategyValidations[0] ?? null;

  const activeBaselineRun = strategyBaselines.find((r) => isActiveStatus(r.status)) ?? null;
  const activeOptimizationRun = strategyOptimizations.find((r) => isActiveStatus(r.status)) ?? null;

  const steps: WorkflowStep[] = useMemo(() => {
    if (!selectedStrategy) return [];

    const readinessStatus: StepStatus = !strategy
      ? 'not_started'
      : strategy.readiness === 'ready'
      ? 'passed'
      : strategy.readiness === 'warning'
      ? 'blocked'
      : 'failed';

    let baselineStatus: StepStatus = 'not_started';
    let baselineMsg = 'No baseline run found for this strategy.';
    let baselineTs: string | null = null;
    let baselineHref: string | undefined;
    if (latestBaseline) {
      baselineTs = latestBaseline.created_at;
      baselineHref = `/baseline/${latestBaseline.id}`;
      if (isActiveStatus(latestBaseline.status)) {
        baselineStatus = 'running';
        baselineMsg = 'Baseline run is active.';
      } else if (isCompleted(latestBaseline.status)) {
        const cls = latestBaseline.classification;
        if (isRejected(cls)) {
          baselineStatus = 'failed';
          baselineMsg = `Rejected (${cls ?? 'no classification'}).`;
        } else {
          baselineStatus = 'passed';
          baselineMsg = cls ? `Classification: ${cls}` : 'Baseline completed.';
        }
      } else if (isFailed(latestBaseline.status)) {
        baselineStatus = 'failed';
        baselineMsg = `Pipeline failed: ${latestBaseline.status}`;
      } else {
        baselineStatus = 'blocked';
        baselineMsg = `Status: ${latestBaseline.status}`;
      }
    }

    let optStatus: StepStatus = 'not_started';
    let optMsg = 'No optimization run found.';
    let optTs: string | null = null;
    let optHref: string | undefined;
    if (latestOptimization) {
      optTs = latestOptimization.created_at;
      optHref = `/optimization/${latestOptimization.id}`;
      if (isActiveStatus(latestOptimization.status)) {
        optStatus = 'running';
        optMsg = `${latestOptimization.epochs_completed ?? 0} / ${latestOptimization.epochs_requested ?? '?'} epochs`;
      } else if (isCompleted(latestOptimization.status)) {
        const rs = latestOptimization.result_status;
        if (rs === 'optimization_rejected') {
          optStatus = 'failed';
          optMsg = 'Optimization rejected. Optimized result did not improve baseline.';
        } else {
          optStatus = 'passed';
          optMsg = rs ? `Result: ${rs}` : 'Optimization completed.';
        }
      } else if (isFailed(latestOptimization.status)) {
        optStatus = 'failed';
        optMsg = `Pipeline failed: ${latestOptimization.status}`;
      } else {
        optStatus = 'blocked';
        optMsg = `Status: ${latestOptimization.status}`;
      }
    }

    let valStatus: StepStatus = 'not_started';
    let valMsg = 'No validation run found.';
    let valTs: string | null = null;
    let valHref: string | undefined;
    if (latestValidation) {
      valTs = latestValidation.created_at;
      valHref = `/validation/${latestValidation.validation_run_id}`;
      if (isActiveStatus(latestValidation.status)) {
        valStatus = 'running';
        valMsg = 'Validation run is active.';
      } else if (isCompleted(latestValidation.status)) {
        const ds = latestValidation.decision_status ?? latestValidation.summary?.decision_status;
        valStatus = 'passed';
        valMsg = ds ? `Decision: ${String(ds)}` : 'Validation completed.';
      } else if (isFailed(latestValidation.status)) {
        valStatus = 'failed';
        valMsg = `Validation failed: ${latestValidation.status}`;
      } else {
        valStatus = 'blocked';
        valMsg = `Status: ${latestValidation.status}`;
      }
    }

    let decisionStatus: StepStatus = 'not_started';
    let decisionMsg = 'No candidate decision recorded yet.';
    if (latestValidation && valStatus === 'passed') {
      const ds = String(latestValidation.decision_status ?? latestValidation.summary?.decision_status ?? '');
      if (ds.includes('reject') || ds.includes('fail')) {
        decisionStatus = 'failed';
        decisionMsg = `Decision: ${ds}. Strategy is not a validated candidate.`;
      } else if (ds) {
        decisionStatus = 'passed';
        decisionMsg = `Decision recorded: ${ds}. Evidence only — not an approval or live-trading authorization.`;
      }
    }

    return [
      {
        id: 'strategy',
        label: 'Strategy selected',
        status: selectedStrategy ? 'passed' : 'not_started',
        message: selectedStrategy ? `${selectedStrategy} is the active strategy.` : 'Select a strategy to begin.',
      },
      {
        id: 'readiness',
        label: 'Readiness checked',
        status: readinessStatus,
        message: strategy
          ? `Readiness: ${readinessLabel(strategy.readiness)}. ${strategy.issues.length} issue${strategy.issues.length !== 1 ? 's' : ''}, ${strategy.warnings.length} warning${strategy.warnings.length !== 1 ? 's' : ''}.`
          : 'Readiness not available.',
        href: selectedStrategy ? `/strategies/${encodeURIComponent(selectedStrategy)}` : undefined,
      },
      {
        id: 'baseline',
        label: 'Baseline completed',
        status: baselineStatus,
        message: baselineMsg,
        timestamp: baselineTs,
        href: baselineHref,
      },
      {
        id: 'optimization',
        label: 'Optimization completed',
        status: optStatus,
        message: optMsg,
        timestamp: optTs,
        href: optHref,
      },
      {
        id: 'validation',
        label: 'Validation completed',
        status: valStatus,
        message: valMsg,
        timestamp: valTs,
        href: valHref,
      },
      {
        id: 'decision',
        label: 'Candidate decision',
        status: decisionStatus,
        message: decisionMsg,
      },
    ];
  }, [selectedStrategy, strategy, latestBaseline, latestOptimization, latestValidation]);

  const nextActions = useMemo(() => {
    if (!selectedStrategy || !strategy) return [];
    const actions: Array<{ id: string; label: string; description: string; href?: string; tone?: 'primary' | 'secondary' | 'warning' }> = [];

    if (strategy.readiness !== 'ready') {
      actions.push({
        id: 'fix-strategy',
        label: 'Open Strategy',
        description: 'Review strategy readiness issues before running.',
        href: `/strategies/${encodeURIComponent(selectedStrategy)}`,
        tone: 'warning',
      });
    }

    if (latestBaseline) {
      actions.push({
        id: 'view-baseline',
        label: 'View Baseline',
        description: 'Inspect baseline metrics, decision, and pair results.',
        href: `/baseline/${latestBaseline.id}`,
        tone: 'secondary',
      });
    }

    if (latestOptimization) {
      actions.push({
        id: 'view-opt',
        label: 'View Optimization',
        description: 'Inspect optimization trials and baseline comparison.',
        href: `/optimization/${latestOptimization.id}`,
        tone: 'secondary',
      });
    }

    if (latestValidation) {
      actions.push({
        id: 'view-val',
        label: 'View Validation',
        description: 'Review OOS, WFO, and robustness evidence.',
        href: `/validation/${latestValidation.validation_run_id}`,
        tone: 'secondary',
      });
    }

    return actions;
  }, [selectedStrategy, strategy, latestBaseline, latestOptimization, latestValidation]);

  const hasActiveRun = Boolean(activeBaselineRun || activeOptimizationRun);

  const baselineMetrics = useMemo(() => {
    if (!latestBaseline) return null;
    return latestBaseline;
  }, [latestBaseline]);

  return (
    <AppShell
      pageTitle="Strategy Journey"
      onRefresh={() => { void load(true); }}
      refreshDisabled={refreshing}
    >
      <div className="space-y-6">
        <PageHeader
          title="Strategy Journey"
          description="Select a strategy and see its full discovery lifecycle — from readiness check through baseline, optimization, and validation evidence."
          actions={
            state.loadedAt ? (
              <span className="text-xs text-[var(--app-text-subtle)]">Updated {fmtTs(state.loadedAt)}</span>
            ) : null
          }
        />

        {state.errors.length > 0 && (
          <ErrorBanner title="Some journey data could not be loaded">
            <ul className="list-inside list-disc space-y-1">
              {state.errors.map((e, i) => <li key={i}>{e}</li>)}
            </ul>
          </ErrorBanner>
        )}

        <ControlledFailureBanner title="Evidence only — no live trading">
          The Strategy Journey is a read-only inspection surface. No run actions are available here. Every metric and chart reflects real backend data only.
        </ControlledFailureBanner>

        <SectionCard title="Select strategy" description="Choose a strategy to view its discovery lifecycle.">
          {loading ? (
            <LoadingSkeleton lines={2} />
          ) : state.strategies.length === 0 ? (
            <EmptyState
              title="No strategies found"
              description="Import strategies into the backend to see them here."
            />
          ) : (
            <div className="flex flex-wrap items-start gap-4">
              <div className="min-w-0 flex-1">
                <label htmlFor="strategy-select" className="mb-1 block text-xs font-semibold text-[var(--app-text-subtle)]">
                  Strategy
                </label>
                <select
                  id="strategy-select"
                  value={selectedStrategy}
                  onChange={(e) => setSelectedStrategy(e.target.value)}
                  className="h-10 w-full max-w-md rounded-[var(--app-radius)] border border-[var(--app-border)] bg-[var(--app-surface-muted)] px-3 text-sm text-[var(--app-text)] outline-none focus:border-[var(--app-accent-border)]"
                >
                  {state.strategies.map((s) => (
                    <option key={s.strategy_name} value={s.strategy_name}>
                      {s.strategy_name}
                    </option>
                  ))}
                </select>
              </div>
              {strategy && (
                <div className="flex items-center gap-3 pt-5">
                  <StatusBadge
                    status={strategy.readiness}
                    tone={readinessTone(strategy.readiness)}
                    label={readinessLabel(strategy.readiness)}
                  />
                  {strategy.params_summary?.timeframe && (
                    <span className="rounded border border-[var(--app-border)] bg-[var(--app-surface-muted)] px-2 py-0.5 text-xs text-[var(--app-text-muted)]">
                      {strategy.params_summary.timeframe}
                    </span>
                  )}
                  {strategy.has_sidecar && (
                    <span className="rounded border border-[rgb(34_197_94_/_0.32)] bg-[rgb(34_197_94_/_0.10)] px-2 py-0.5 text-xs text-[var(--app-success)]">
                      Sidecar ✓
                    </span>
                  )}
                </div>
              )}
            </div>
          )}
        </SectionCard>

        {selectedStrategy && !loading && (
          <>
            {hasActiveRun && (
              <SectionCard title="Live run" description="A run is currently active. Polling every 2 seconds.">
                <div className="space-y-3">
                  {activeBaselineRun && (
                    <LiveRunPanel runType="baseline" runId={activeBaselineRun.id} label="Baseline run (active)" />
                  )}
                  {activeOptimizationRun && (
                    <LiveRunPanel runType="optimization" runId={activeOptimizationRun.id} label="Optimization run (active)" />
                  )}
                </div>
              </SectionCard>
            )}

            <div className="grid gap-6 xl:grid-cols-3">
              <div className="xl:col-span-2">
                <SectionCard
                  title="Journey timeline"
                  description="Status of each lifecycle stage based on real backend data. Not started means no backend record was found."
                >
                  {steps.length === 0 ? (
                    <EmptyState title="No steps to show" description="Select a strategy to see its journey." />
                  ) : (
                    <WorkflowStepper steps={steps} orientation="vertical" />
                  )}
                </SectionCard>
              </div>

              <div className="space-y-4">
                <SectionCard title="Evidence summary" description="Latest run records for this strategy.">
                  <div className="space-y-3">
                    <EvidenceRow
                      label="Baseline runs"
                      count={strategyBaselines.length}
                      latest={latestBaseline ? {
                        status: latestBaseline.classification ?? latestBaseline.status,
                        href: `/baseline/${latestBaseline.id}`,
                        ts: latestBaseline.created_at,
                      } : null}
                    />
                    <EvidenceRow
                      label="Optimization runs"
                      count={strategyOptimizations.length}
                      latest={latestOptimization ? {
                        status: latestOptimization.result_status ?? latestOptimization.status,
                        href: `/optimization/${latestOptimization.id}`,
                        ts: latestOptimization.created_at,
                      } : null}
                    />
                    <EvidenceRow
                      label="Validation runs"
                      count={strategyValidations.length}
                      latest={latestValidation ? {
                        status: latestValidation.decision_status ?? latestValidation.status,
                        href: `/validation/${latestValidation.validation_run_id}`,
                        ts: latestValidation.created_at,
                      } : null}
                    />
                  </div>
                </SectionCard>

                {nextActions.length > 0 && (
                  <NextActionPanel
                    title="Next safe action"
                    message="Select an action below to navigate to the relevant detail page."
                    actions={nextActions}
                  />
                )}
              </div>
            </div>

            {baselineMetrics && (
              <SectionCard
                title="Latest baseline snapshot"
                description={`Quick-view of the most recent baseline run (${latestBaseline?.id ?? ''}). Open the baseline detail for full evidence.`}
              >
                <div className="grid gap-4 md:grid-cols-2 xl:grid-cols-4">
                  <MetricCard
                    label="Status"
                    value={latestBaseline?.classification ?? latestBaseline?.status ?? 'Unknown'}
                  />
                  <MetricCard
                    label="Timeframe"
                    value={latestBaseline?.timeframe ?? 'Not recorded'}
                  />
                  <MetricCard
                    label="Created"
                    value={fmtTs(latestBaseline?.created_at)}
                  />
                  <MetricCard
                    label="Updated"
                    value={fmtTs(latestBaseline?.updated_at)}
                  />
                </div>
                <div className="mt-4">
                  <a
                    href={`/baseline/${latestBaseline?.id}`}
                    className="inline-flex h-9 items-center rounded-[var(--app-radius)] border border-[var(--app-border)] bg-[var(--app-surface-muted)] px-3.5 text-sm text-[var(--app-text-muted)] hover:text-[var(--app-text)] transition-colors"
                  >
                    Open full baseline detail →
                  </a>
                </div>
              </SectionCard>
            )}

            {strategy && strategy.issues.length > 0 && (
              <SectionCard
                title="Strategy issues"
                description="Readiness issues detected by the backend. Resolve critical and error issues before running."
              >
                <div className="space-y-2">
                  {strategy.issues.map((issue, idx) => {
                    const tone =
                      issue.severity === 'critical' || issue.severity === 'error'
                        ? 'danger'
                        : issue.severity === 'warning'
                        ? 'warning'
                        : 'neutral';
                    return (
                      <div key={idx} className="rounded-[var(--app-radius)] border border-[var(--app-border)] bg-[var(--app-surface-muted)] p-3">
                        <div className="flex flex-wrap items-center gap-2">
                          <StatusBadge status={issue.severity} tone={tone as 'danger' | 'warning' | 'neutral'} />
                          <span className="font-mono text-xs text-[var(--app-text-muted)]">{issue.code}</span>
                        </div>
                        <p className="mt-2 text-sm leading-6 text-[var(--app-text)]">{issue.message}</p>
                      </div>
                    );
                  })}
                </div>
              </SectionCard>
            )}
          </>
        )}
      </div>
    </AppShell>
  );
}

function EvidenceRow({
  label,
  count,
  latest,
}: {
  label: string;
  count: number;
  latest: { status: string | null; href: string; ts: string } | null;
}) {
  return (
    <div className="flex items-center justify-between gap-3 rounded-[var(--app-radius)] border border-[var(--app-border)] bg-[var(--app-surface-muted)] p-3">
      <div className="min-w-0">
        <p className="text-xs font-semibold text-[var(--app-text)]">{label}</p>
        {latest ? (
          <p className="mt-0.5 text-[11px] text-[var(--app-text-subtle)]">
            {fmtTs(latest.ts)}
          </p>
        ) : (
          <p className="mt-0.5 text-[11px] text-[var(--app-text-subtle)]">Not started</p>
        )}
      </div>
      <div className="flex shrink-0 items-center gap-2">
        <span className="font-mono text-xs text-[var(--app-text-muted)]">{count}</span>
        {latest?.status && (
          <StatusBadge status={latest.status} />
        )}
        {latest && (
          <a
            href={latest.href}
            className="rounded border border-[var(--app-border)] bg-[var(--app-surface)] px-2 py-0.5 text-[11px] text-[var(--app-text-muted)] hover:text-[var(--app-accent)] transition-colors"
          >
            View
          </a>
        )}
      </div>
    </div>
  );
}

'use client';

import { useCallback, useEffect, useState } from 'react';
import { useParams } from 'next/navigation';
import AppShell from '@/components/AppShell';
import Button from '@/components/Button';
import ControlledFailureBanner from '@/components/ControlledFailureBanner';
import CopyButton from '@/components/CopyButton';
import EmptyState from '@/components/EmptyState';
import ErrorBanner from '@/components/ErrorBanner';
import LoadingSkeleton from '@/components/LoadingSkeleton';
import OOSValidationCard from '@/components/OOSValidationCard';
import PageHeader from '@/components/PageHeader';
import RobustnessValidationCard from '@/components/RobustnessValidationCard';
import SectionCard from '@/components/SectionCard';
import StatusBadge from '@/components/StatusBadge';
import ValidationDecisionBanner from '@/components/ValidationDecisionBanner';
import WFOValidationCard from '@/components/WFOValidationCard';
import { getValidationRun, getValidationEvidence } from '@/lib/api/validation';
import type { ValidationRunDetail, ValidationEvidence, ValidationDecision } from '@/lib/api/types';

function fmtTs(ts: string | null | undefined): string {
  if (!ts) return '—';
  try {
    return new Date(ts).toLocaleString(undefined, {
      month: 'short', day: 'numeric', year: 'numeric',
      hour: '2-digit', minute: '2-digit',
    });
  } catch {
    return ts;
  }
}

function Field({ label, children, mono = false }: { label: string; children: React.ReactNode; mono?: boolean }) {
  return (
    <div>
      <p className="text-xs font-semibold text-[var(--app-text-subtle)]">{label}</p>
      <div className={`mt-1 text-sm text-[var(--app-text)] ${mono ? 'font-mono' : ''}`}>
        {children}
      </div>
    </div>
  );
}

export default function ValidationDetailPage() {
  const params = useParams();
  const validationRunId = params.validationRunId as string;

  const [detail, setDetail] = useState<ValidationRunDetail | null>(null);
  const [evidence, setEvidence] = useState<ValidationEvidence[] | null>(null);
  const [loading, setLoading] = useState(true);
  const [refreshing, setRefreshing] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const load = useCallback(async (markRefreshing = true) => {
    if (markRefreshing) setRefreshing(true);
    setError(null);

    const [detailResult, evidenceResult] = await Promise.all([
      getValidationRun(validationRunId),
      getValidationEvidence(validationRunId),
    ]);

    if (detailResult.success) {
      setDetail(detailResult.data);
    } else {
      setError(detailResult.error.message);
    }

    if (evidenceResult.success) {
      setEvidence(evidenceResult.data.evidence);
    }

    setLoading(false);
    if (markRefreshing) setRefreshing(false);
  }, [validationRunId]);

  useEffect(() => {
    const t = window.setTimeout(() => { void load(false); }, 0);
    return () => window.clearTimeout(t);
  }, [load]);

  const oosEvidence = evidence?.find((e) => e.evidence_type === 'oos');
  const wfoSummary = evidence?.find((e) => e.evidence_type === 'wfo_summary');
  const wfoWindows = evidence?.filter((e) => e.evidence_type === 'wfo_window');
  const robustnessChecks = evidence?.filter((e) => e.evidence_type === 'robustness');
  const sensitivityChecks = evidence?.filter((e) => e.evidence_type === 'sensitivity');

  const finalDecision = detail?.final_decision as ValidationDecision | null | undefined;

  if (loading) {
    return (
      <AppShell pageTitle="Validation Detail">
        <div className="space-y-6">
          <PageHeader title="Validation detail" description="Loading validation evidence…" />
          <LoadingSkeleton lines={6} />
        </div>
      </AppShell>
    );
  }

  if (error) {
    return (
      <AppShell pageTitle="Validation Detail">
        <div className="space-y-6">
          <PageHeader title="Validation detail" description="Validation evidence could not be loaded." />
          <ErrorBanner title="Error loading validation data">
            <p>{error}</p>
          </ErrorBanner>
          <div>
            <Button onClick={() => { void load(true); }}>Retry</Button>
          </div>
        </div>
      </AppShell>
    );
  }

  if (!detail) {
    return (
      <AppShell pageTitle="Validation Detail">
        <div className="space-y-6">
          <PageHeader title="Validation detail" />
          <SectionCard>
            <EmptyState
              title="Validation run not found"
              description={`Validation run ${validationRunId} could not be found.`}
            />
          </SectionCard>
        </div>
      </AppShell>
    );
  }

  return (
    <AppShell
      pageTitle="Validation Detail"
      onRefresh={() => { void load(true); }}
      refreshDisabled={refreshing}
    >
      <div className="space-y-6">
        <PageHeader
          title="Validation detail"
          description="Read-only validation evidence. OOS, WFO, and robustness results are from real backend data only."
          actions={
            <>
              <CopyButton value={validationRunId} label="Copy run ID" />
              <Button variant="secondary" onClick={() => { void load(true); }} disabled={refreshing}>
                Refresh
              </Button>
            </>
          }
        />

        <ControlledFailureBanner title="Validation is evidence only">
          Validation is evidence only. It is not strategy approval, export, live-trading authorization, or a guarantee of future performance.
        </ControlledFailureBanner>

        <ValidationDecisionBanner decisionStatus={detail.run.decision_status} />

        <SectionCard title="Run summary" description="Identity, scope, and status metadata for this validation run.">
          <div className="grid gap-4 md:grid-cols-2 xl:grid-cols-4">
            <Field label="Validation run ID" mono>
              <span className="truncate block">{validationRunId}</span>
            </Field>
            <Field label="Strategy">
              {detail.run.strategy_name || '—'}
            </Field>
            <Field label="Source type">
              {detail.run.source_type || '—'}
            </Field>
            <Field label="Source run ID" mono>
              {detail.run.source_run_id
                ? <span className="flex items-center gap-2">
                    <span className="truncate">{detail.run.source_run_id}</span>
                    <CopyButton value={detail.run.source_run_id} label="Copy" />
                  </span>
                : '—'}
            </Field>
            <Field label="Status">
              <StatusBadge status={detail.run.status} />
            </Field>
            <Field label="Decision status">
              {detail.run.decision_status
                ? <StatusBadge status={detail.run.decision_status} />
                : <span className="text-[var(--app-text-subtle)]">Not recorded</span>}
            </Field>
            <Field label="Pairs">
              {detail.run.pairs?.join(', ') || '—'}
            </Field>
            <Field label="Timeframe">
              {detail.run.timeframe || '—'}
            </Field>
            <Field label="Exchange">
              {detail.run.exchange || '—'}
            </Field>
            <Field label="Risk profile">
              {detail.run.risk_profile || '—'}
            </Field>
            <Field label="Created">
              {fmtTs(detail.run.created_at)}
            </Field>
            <Field label="Updated">
              {fmtTs(detail.run.updated_at)}
            </Field>
          </div>
          {detail.run.oos_timerange && (
            <div className="mt-4">
              <Field label="OOS timerange" mono>
                {detail.run.oos_timerange}
              </Field>
            </div>
          )}
        </SectionCard>

        <div className="grid gap-6 xl:grid-cols-2">
          <OOSValidationCard evidence={oosEvidence} />
          <WFOValidationCard evidence={wfoSummary} windows={wfoWindows} />
        </div>

        <RobustnessValidationCard checks={robustnessChecks} />

        {sensitivityChecks && sensitivityChecks.length > 0 && (
          <SectionCard title="Sensitivity checks" description="Sensitivity analysis tests how the strategy responds to parameter variations.">
            <div className="space-y-2">
              {sensitivityChecks.map((check, idx) => {
                const isPassed = check.status === 'sensitivity_passed';
                return (
                  <div
                    key={idx}
                    className="rounded-[var(--app-radius)] border border-[var(--app-border)] bg-[var(--app-surface-muted)] p-3"
                  >
                    <div className="flex items-center justify-between gap-3">
                      <p className="text-sm font-medium text-[var(--app-text)]">
                        {check.check_name ?? `Check ${idx + 1}`}
                      </p>
                      <StatusBadge
                        status={check.status}
                        tone={isPassed ? 'success' : 'warning'}
                        label={isPassed ? 'Passed' : check.status}
                      />
                    </div>
                    {check.issues && check.issues.length > 0 && (
                      <ul className="mt-2 space-y-1">
                        {check.issues.map((issue, i) => (
                          <li key={i} className="text-xs text-[var(--app-text-muted)] flex gap-2">
                            <span className="text-[var(--app-warning)] shrink-0">•</span>
                            {issue.message}
                          </li>
                        ))}
                      </ul>
                    )}
                  </div>
                );
              })}
            </div>
          </SectionCard>
        )}

        {finalDecision && (
          <SectionCard
            title="Final decision"
            description="The validation engine's final evidence-based decision. This is not an approval."
          >
            <div className="space-y-4">
              <div className="grid gap-4 md:grid-cols-3">
                <div>
                  <p className="text-xs text-[var(--app-text-subtle)]">Decision status</p>
                  <div className="mt-1">
                    <StatusBadge status={finalDecision.decision_status} />
                  </div>
                </div>
                {finalDecision.confidence_score != null && (
                  <div>
                    <p className="text-xs text-[var(--app-text-subtle)]">Confidence score</p>
                    <p className="mt-1 text-sm font-semibold text-[var(--app-text)]">
                      {Number(finalDecision.confidence_score).toFixed(3)}
                    </p>
                  </div>
                )}
                {finalDecision.policy_name && (
                  <div>
                    <p className="text-xs text-[var(--app-text-subtle)]">Policy</p>
                    <p className="mt-1 text-sm text-[var(--app-text)]">{finalDecision.policy_name}</p>
                  </div>
                )}
              </div>
              {finalDecision.blocking_failures && finalDecision.blocking_failures.length > 0 && (
                <div>
                  <p className="text-xs font-semibold text-[var(--app-danger)] mb-1">Blocking failures</p>
                  <ul className="space-y-1">
                    {finalDecision.blocking_failures.map((f, i) => (
                      <li key={i} className="text-xs text-[var(--app-text-muted)] flex gap-2">
                        <span className="text-[var(--app-danger)] shrink-0">•</span>{f}
                      </li>
                    ))}
                  </ul>
                </div>
              )}
              {finalDecision.reasons && finalDecision.reasons.length > 0 && (
                <div>
                  <p className="text-xs font-semibold text-[var(--app-text-muted)] mb-1">Reasons</p>
                  <ul className="space-y-1">
                    {finalDecision.reasons.map((r, i) => (
                      <li key={i} className="text-xs text-[var(--app-text-muted)] flex gap-2">
                        <span className="text-[var(--app-text-subtle)] shrink-0">•</span>{r}
                      </li>
                    ))}
                  </ul>
                </div>
              )}
              {finalDecision.warnings && finalDecision.warnings.length > 0 && (
                <div>
                  <p className="text-xs font-semibold text-[var(--app-warning)] mb-1">Warnings</p>
                  <ul className="space-y-1">
                    {finalDecision.warnings.map((w, i) => (
                      <li key={i} className="text-xs text-[var(--app-text-muted)] flex gap-2">
                        <span className="text-[var(--app-warning)] shrink-0">•</span>{w}
                      </li>
                    ))}
                  </ul>
                </div>
              )}
              {finalDecision.next_actions && finalDecision.next_actions.length > 0 && (
                <div>
                  <p className="text-xs font-semibold text-[var(--app-info)] mb-1">Next actions</p>
                  <ul className="space-y-1">
                    {finalDecision.next_actions.map((a, i) => (
                      <li key={i} className="text-xs text-[var(--app-text-muted)] flex gap-2">
                        <span className="text-[var(--app-info)] shrink-0">→</span>{a}
                      </li>
                    ))}
                  </ul>
                </div>
              )}
            </div>
          </SectionCard>
        )}

        {(detail.warnings.length > 0 || detail.errors.length > 0 || detail.next_actions.length > 0) && (
          <SectionCard title="Warnings, errors, and next actions" description="Validation pipeline messages and suggested next steps.">
            <div className="space-y-4">
              {detail.errors.length > 0 && (
                <div>
                  <p className="text-xs font-semibold text-[var(--app-danger)] mb-1">Errors</p>
                  <ul className="space-y-1">
                    {detail.errors.map((e, idx) => (
                      <li key={idx} className="text-sm text-[var(--app-text-muted)] flex gap-2">
                        <span className="text-[var(--app-danger)] shrink-0">•</span>{e}
                      </li>
                    ))}
                  </ul>
                </div>
              )}
              {detail.warnings.length > 0 && (
                <div>
                  <p className="text-xs font-semibold text-[var(--app-warning)] mb-1">Warnings</p>
                  <ul className="space-y-1">
                    {detail.warnings.map((w, idx) => (
                      <li key={idx} className="text-sm text-[var(--app-text-muted)] flex gap-2">
                        <span className="text-[var(--app-warning)] shrink-0">•</span>{w}
                      </li>
                    ))}
                  </ul>
                </div>
              )}
              {detail.next_actions.length > 0 && (
                <div>
                  <p className="text-xs font-semibold text-[var(--app-info)] mb-1">Next actions</p>
                  <ul className="space-y-1">
                    {detail.next_actions.map((a, idx) => (
                      <li key={idx} className="text-sm text-[var(--app-text-muted)] flex gap-2">
                        <span className="text-[var(--app-info)] shrink-0">→</span>{a}
                      </li>
                    ))}
                  </ul>
                </div>
              )}
            </div>
          </SectionCard>
        )}

        {detail.report_path && (
          <SectionCard title="Report artifact" description="Local artifact path for the validation report file.">
            <div className="flex items-center gap-2">
              <span className="font-mono text-xs text-[var(--app-text-muted)]">{detail.report_path}</span>
              <CopyButton value={detail.report_path} label="Copy path" />
            </div>
          </SectionCard>
        )}
      </div>
    </AppShell>
  );
}

